const input = $input.first().json || {};
const headers = input.headers || {};
const body = input.body || input;
const secret = headers['x-webhook-secret'] || headers['X-Webhook-Secret'] || '';
// Secret-validatie gebeurt in het platform dat deze interne webhook aanroept.
// Deze n8n-installatie blokkeert env access in Code-nodes; env access hier gebruiken laat de workflow falen.
if (!secret) {
  throw new Error('Niet geautoriseerd');
}

function esc(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}
function nl2br(value) {
  return esc(value).replace(/\n/g, '<br>');
}
function list(value) {
  if (!Array.isArray(value) || value.length === 0) return '<em>Geen</em>';
  return '<ul>' + value.map((item) => `<li>${esc(typeof item === 'string' ? item : JSON.stringify(item))}</li>`).join('') + '</ul>';
}

const job = body.job || {};
const result = body.result || {};
const contact = job.contactName || job.context?.contact?.name || 'Onbekende kijker';
const property = job.propertyTitle || job.context?.property?.title || 'onbekende woning';
const subject = body.subject || `AI-belgesprek: ${contact} - ${property}`;
const requestedFollowUp = result.requestedFollowUp ? JSON.stringify(result.requestedFollowUp, null, 2) : '';
const links = Array.isArray(result.proposedLinks) ? result.proposedLinks : [];
const questions = Array.isArray(result.customerQuestions) ? result.customerQuestions : [];
const opportunities = Array.isArray(result.detectedOpportunities) ? result.detectedOpportunities : [];

const html = `
<h2>AI-belgesprek afgerond</h2>
<p><strong>Contact:</strong> ${esc(contact)}<br>
<strong>Telefoon:</strong> ${esc(job.contactPhone || job.context?.contact?.phone || '')}<br>
<strong>Woning:</strong> ${esc(property)}<br>
<strong>Uitkomst:</strong> ${esc(result.outcome || 'onbekend')}<br>
<strong>Duur:</strong> ${esc(result.durationSeconds || '')} seconden</p>

<h3>Samenvatting</h3>
<p>${nl2br(result.summary || 'Geen samenvatting ontvangen.')}</p>

<h3>Klantvragen</h3>
${list(questions)}

<h3>Kansen/signalen</h3>
${list(opportunities)}

<h3>Gewenste opvolging</h3>
<pre>${esc(requestedFollowUp || 'Geen specifieke opvolging')}</pre>

<h3>Voorgestelde links</h3>
${links.length ? '<ul>' + links.map((link) => `<li><a href="${esc(link.url || '')}">${esc(link.title || link.url || 'Link')}</a> ${link.purpose ? `- ${esc(link.purpose)}` : ''}</li>`).join('') + '</ul>' : '<em>Geen</em>'}

${result.transcript ? `<h3>Transcript</h3><p>${nl2br(result.transcript)}</p>` : ''}
`;

return [{ json: { to: body.to || 'info@devreemakelaardij.nl', subject, html } }];
